  1→/**
  2→ * Agent Route Handlers
  3→ *
  4→ * HTTP handler factory for the agent CRUD module. Each handler resolves
  5→ * identity from Better Auth session, validates input, delegates to
  6→ * query functions, and returns JSON responses.
  7→ *
  8→ * All handlers follow the wide-event observability pattern via
  9→ * trace.getActiveSpan()?.setAttribute().
 10→ */
 11→import { RecordId } from "surrealdb";
 12→import { trace } from "@opentelemetry/api";
 13→import { HttpError } from "../http/errors";
 14→import { jsonError, jsonResponse } from "../http/response";
 15→import type { ServerDependencies } from "../runtime/types";
 16→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
 17→import { log } from "../telemetry/logger";
 18→import {
 19→  listAgents,
 20→  createAgentTransaction,
 21→  getAgentDetail,
 22→  deleteAgentTransaction,
 23→  checkAgentName,
 24→} from "./agent-queries";
 25→import type { CreateAgentInput } from "./types";
 26→
 27→// ---------------------------------------------------------------------------
 28→// Identity resolution (session -> person -> identity)
 29→// ---------------------------------------------------------------------------
 30→
 31→type IdentityInfo = {
 32→  identityRecord: RecordId<"identity", string>;
 33→};
 34→
 35→async function resolveIdentityFromSession(
 36→  deps: ServerDependencies,
 37→  request: Request,
 38→): Promise<IdentityInfo | Response> {
 39→  const session = await deps.auth.api.getSession({ headers: request.headers });
 40→  if (!session?.user?.id) {
 41→    return jsonError("authentication required", 401);
 42→  }
 43→
 44→  const personRecord = new RecordId("person", session.user.id);
 45→
 46→  const [identityRows] = await deps.surreal.query<[RecordId<"identity", string>[]]>(
 47→    "SELECT VALUE in FROM identity_person WHERE out = $person LIMIT 1;",
 48→    { person: personRecord },
 49→  );
 50→  const identityRecord = identityRows[0] as RecordId<"identity", string> | undefined;
 51→  if (!identityRecord) {
 52→    return jsonError("identity not found for user", 500);
 53→  }
 54→
 55→  return { identityRecord };
 56→}
 57→
 58→// ---------------------------------------------------------------------------
 59→// Shared helpers
 60→// ---------------------------------------------------------------------------
 61→
 62→function isResponse(value: unknown): value is Response {
 63→  return value instanceof Response;
 64→}
 65→
 66→async function resolveWorkspace(
 67→  deps: ServerDependencies,
 68→  workspaceId: string,
 69→  logEvent: string,
 70→): Promise<RecordId<"workspace", string> | Response> {
 71→  try {
 72→    return await resolveWorkspaceRecord(deps.surreal, workspaceId);
 73→  } catch (error) {
 74→    if (error instanceof HttpError) {
 75→      return jsonError(error.message, error.status);
 76→    }
 77→    log.error(logEvent, "Failed to resolve workspace", error, { workspaceId });
 78→    return jsonError("failed to resolve workspace", 500);
 79→  }
 80→}
 81→
 82→const VALID_RUNTIMES: ReadonlySet<string> = new Set(["sandbox", "external"]);
 83→
 84→function isValidRuntime(runtime: unknown): runtime is "sandbox" | "external" {
 85→  return typeof runtime === "string" && VALID_RUNTIMES.has(runtime);
 86→}
