251→// ---------------------------------------------------------------------------
252→// DELETE /api/workspaces/:workspaceId/agents/:agentId
253→// ---------------------------------------------------------------------------
254→
255→async function handleDeleteAgent(
256→  deps: ServerDependencies,
257→  workspaceId: string,
258→  agentId: string,
259→  request: Request,
260→): Promise<Response> {
261→  const identityOrError = await resolveIdentityFromSession(deps, request);
262→  if (isResponse(identityOrError)) return identityOrError;
263→
264→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "agent.delete.workspace_resolve.failed");
265→  if (isResponse(workspaceOrError)) return workspaceOrError;
266→
267→  let body: Record<string, unknown>;
268→  try {
269→    body = await request.json() as Record<string, unknown>;
270→  } catch {
271→    return jsonError("invalid JSON body", 400);
272→  }
273→
274→  const confirmName = body.confirm_name;
275→  if (typeof confirmName !== "string" || confirmName.trim().length === 0) {
276→    return jsonError("confirm_name is required", 400);
277→  }
278→
279→  try {
280→    const result = await deleteAgentTransaction(deps.surreal, workspaceId, agentId, confirmName);
281→    trace.getActiveSpan()?.setAttribute("agent.delete.agent_id", agentId);
282→    return jsonResponse(result, 200);
283→  } catch (error) {
284→    if (error instanceof HttpError) {
285→      return jsonError(error.message, error.status);
286→    }
287→    log.error("agent.delete.failed", "Failed to delete agent", error, { workspaceId, agentId });
288→    return jsonError("failed to delete agent", 500);
289→  }
290→}
