292→// ---------------------------------------------------------------------------
293→// GET /api/workspaces/:workspaceId/agents/check-name?name=...
294→// ---------------------------------------------------------------------------
295→
296→async function handleCheckAgentName(
297→  deps: ServerDependencies,
298→  workspaceId: string,
299→  request: Request,
300→): Promise<Response> {
301→  const identityOrError = await resolveIdentityFromSession(deps, request);
302→  if (isResponse(identityOrError)) return identityOrError;
303→
304→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "agent.check_name.workspace_resolve.failed");
305→  if (isResponse(workspaceOrError)) return workspaceOrError;
306→
307→  const url = new URL(request.url);
308→  const name = url.searchParams.get("name");
309→  if (!name || name.trim().length === 0) {
310→    return jsonError("name query parameter is required", 400);
311→  }
312→
313→  try {
314→    const available = await checkAgentName(deps.surreal, workspaceId, name.trim());
315→    trace.getActiveSpan()?.setAttribute("agent.check_name.available", available);
316→    return jsonResponse({ available }, 200);
317→  } catch (error) {
318→    log.error("agent.check_name.failed", "Failed to check agent name", error, { workspaceId });
319→    return jsonError("failed to check agent name", 500);
320→  }
321→}
