 57→  createAgent: (input: CreateAgentInput) => Promise<CreateAgentResult | undefined>;
 58→  deleteAgent: (agentId: string, confirmName: string) => Promise<boolean>;
 59→  fetchDetail: (agentId: string) => Promise<AgentDetailResult | undefined>;
 60→  checkName: (name: string) => Promise<boolean>;
 61→  clearError: () => void;
