 1→import { useCallback, useEffect, useState } from "react";
 2→import { useWorkspaceState } from "../stores/workspace-state";
 3→
 4→export type AgentRuntime = "osabio" | "sandbox" | "external";
 5→
 6→export type AgentListItem = {
 7→  id: string;
 8→  name: string;
 9→  description?: string;
10→  runtime: AgentRuntime;
11→  model?: string;
12→  identity_id: string;
13→  created_at: string;
14→};
15→
16→type UseAgentsReturn = {
17→  agents: AgentListItem[];
18→  isLoading: boolean;
19→  error?: string;
20→  refresh: () => void;
21→};
22→
23→export function buildAgentsUrl(workspaceId: string): string {
24→  return `/api/workspaces/${encodeURIComponent(workspaceId)}/agents`;
25→}
26→
27→export function groupByRuntime(agents: AgentListItem[]): Record<AgentRuntime, AgentListItem[]> {
28→  const groups: Record<AgentRuntime, AgentListItem[]> = { osabio: [], sandbox: [], external: [] };
29→  for (const agent of agents) {
30→    const bucket = groups[agent.runtime];
31→    if (bucket) bucket.push(agent);
32→  }
33→  return groups;
34→}
35→
36→export function useAgents(): UseAgentsReturn {
37→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
38→  const [agents, setAgents] = useState<AgentListItem[]>([]);
39→  const [isLoading, setIsLoading] = useState(false);
40→  const [error, setError] = useState<string | undefined>();
41→
42→  const fetchAgents = useCallback(async () => {
43→    if (!workspaceId) return;
44→
45→    setIsLoading(true);
46→    setError(undefined);
47→
48→    try {
49→      const url = buildAgentsUrl(workspaceId);
50→      const response = await fetch(url);
51→      if (!response.ok) {
52→        const body = await response.text();
53→        throw new Error(body);
54→      }
55→      const data = (await response.json()) as { agents: AgentListItem[] };
56→      setAgents(data.agents);
57→    } catch (err) {
58→      setError(err instanceof Error ? err.message : "Failed to load agents");
59→    } finally {
60→      setIsLoading(false);
61→    }
62→  }, [workspaceId]);
63→
64→  useEffect(() => {
65→    if (!workspaceId) return;
66→    void fetchAgents();
67→  }, [workspaceId, fetchAgents]);
68→
69→  const refresh = useCallback(() => {
70→    void fetchAgents();
71→  }, [fetchAgents]);
72→
73→  return { agents, isLoading, error, refresh };
74→}
