421→// Delete agent (atomic transaction)
422→// ---------------------------------------------------------------------------
423→
424→/**
425→ * Delete an agent and all associated records atomically.
426→ *
427→ * Validates:
428→ * - Agent exists in workspace
429→ * - Agent is not a osabio-managed agent
430→ * - Confirmation name matches agent name
431→ *
432→ * Deletes:
433→ * 1. authorized_to edges from identity
434→ * 2. proxy_token records for identity
435→ * 3. member_of edges from identity to workspace
436→ * 4. identity_agent edges to agent
437→ * 5. identity record
438→ * 6. agent record
439→ */
440→export async function deleteAgentTransaction(
441→  surreal: Surreal,
442→  workspaceId: string,
443→  agentId: string,
444→  confirmName: string,
445→): Promise<DeleteAgentResult> {
446→  const workspaceRecord = new RecordId("workspace", workspaceId);
447→  const agentRecord = new RecordId("agent", agentId);
448→
449→  // Validate agent exists and fetch identity
450→  const [agentRows, identityRows] = await surreal
451→    .query<[
452→      Array<{ id: RecordId; name: string; runtime: string }>,
453→      Array<{ id: RecordId<"identity", string> }>,
454→    ]>(
455→      `SELECT id, name, runtime FROM $agent;
456→
457→       SELECT VALUE in FROM identity_agent
458→       WHERE out = $agent
459→       AND in IN (
460→         SELECT VALUE in FROM member_of WHERE out = $ws AND in.type = 'agent'
461→       )
462→       LIMIT 1;`,
463→      { agent: agentRecord, ws: workspaceRecord },
464→    );
465→
466→  if (agentRows.length === 0) {
467→    throw new HttpError(404, "Agent not found");
468→  }
469→
470→  const agent = agentRows[0];
471→
472→  if (agent.runtime === "osabio") {
473→    throw new HttpError(403, "Cannot delete osabio-managed agents");
474→  }
475→
476→  if (agent.name !== confirmName) {
477→    throw new HttpError(
478→      400,
479→      `Confirmation name '${confirmName}' does not match agent name '${agent.name}'`,
480→    );
481→  }
482→
483→  if (identityRows.length === 0) {
484→    throw new HttpError(404, "Agent identity not found in workspace");
485→  }
486→
487→  const identityRecord = identityRows[0] as unknown as RecordId<"identity", string>;
488→
489→  // Execute deletion in a single transaction
490→  await surreal.query(
491→    `BEGIN TRANSACTION;
492→     DELETE FROM authorized_to WHERE in = $identity;
493→     DELETE FROM proxy_token WHERE identity = $identity;
494→     DELETE FROM member_of WHERE in = $identity AND out = $ws;
495→     DELETE FROM identity_agent WHERE out = $agent;
496→     DELETE $identity;
497→     DELETE $agent;
498→     COMMIT TRANSACTION;`,
499→    {
500→      identity: identityRecord,
501→      agent: agentRecord,
502→      ws: workspaceRecord,
503→    },
504→  );
505→
506→  return {
507→    deleted: true,
508→    sessions_aborted: 0, // Deferred to R2
509→  };
510→}
