513→// Lookup agent in workspace
514→// ---------------------------------------------------------------------------
515→
516→type AgentLookupRow = {
517→  agent_name: string;
518→  agent_runtime: string;
519→};
520→
521→/**
522→ * Look up an agent by ID and verify it belongs to the given workspace.
523→ *
524→ * Uses graph traversal: workspace <- member_of <- identity <- identity_agent -> agent
525→ * Returns `{ name, runtime }` if found, throws HttpError(404) otherwise.
526→ */
527→export async function lookupAgentInWorkspace(
528→  surreal: Surreal,
529→  agentId: string,
530→  workspaceId: string,
531→): Promise<{ name: string; runtime: string }> {
532→  const workspaceRecord = new RecordId("workspace", workspaceId);
533→  const agentRecord = new RecordId("agent", agentId);
534→
535→  const [rows] = await surreal.query<[AgentLookupRow[]]>(
536→    `SELECT out.name AS agent_name, out.runtime AS agent_runtime
537→     FROM identity_agent
538→     WHERE out = $agent
539→     AND in IN (
540→       SELECT VALUE in FROM member_of WHERE out = $ws AND in.type = 'agent'
541→     )
542→     LIMIT 1;`,
543→    { agent: agentRecord, ws: workspaceRecord },
544→  );
545→
546→  if (rows.length === 0) {
547→    throw new HttpError(404, `Agent ${agentId} not found in workspace ${workspaceId}`);
548→  }
549→
550→  return { name: rows[0].agent_name, runtime: rows[0].agent_runtime };
551→}
