  6→// ---------------------------------------------------------------------------
  7→// Create
  8→// ---------------------------------------------------------------------------
  9→
 10→export async function createLearning(input: {
 11→  surreal: Surreal;
 12→  workspaceRecord: RecordId<"workspace", string>;
 13→  learning: CreateLearningInput;
 14→  now: Date;
 15→}): Promise<LearningRecord> {
 16→  const learningRecord = new RecordId("learning", randomUUID());
 17→
 18→  const defaultStatus: LearningStatus = input.learning.source === "human" ? "active" : "pending_approval";
 19→  const status: LearningStatus = input.learning.forceStatus ?? defaultStatus;
 20→  const isActive = status === "active";
 21→
 22→  await input.surreal.create(learningRecord).content({
 23→    text: input.learning.text,
 24→    learning_type: input.learning.learningType,
 25→    status,
 26→    source: input.learning.source,
 27→    priority: input.learning.priority ?? "medium",
 28→    target_agents: input.learning.targetAgents ?? [],
 29→    workspace: input.workspaceRecord,
 30→    ...(input.learning.suggestedBy ? { suggested_by: input.learning.suggestedBy } : {}),
 31→    ...(input.learning.patternConfidence !== undefined ? { pattern_confidence: input.learning.patternConfidence } : {}),
 32→    ...(input.learning.createdBy ? { created_by: new RecordId("identity", input.learning.createdBy) } : {}),
 33→    ...(isActive ? { activated_at: input.now } : {}),
 34→    created_at: input.now,
 35→    updated_at: input.now,
 36→  });
 37→
 38→  // Create evidence edges
 39→  if (input.learning.evidenceIds && input.learning.evidenceIds.length > 0) {
 40→    for (const evidence of input.learning.evidenceIds) {
 41→      const evidenceRecord = new RecordId(evidence.table, evidence.id) as EvidenceTargetRecord;
 42→      await input.surreal
 43→        .relate(learningRecord, new RecordId("learning_evidence", randomUUID()), evidenceRecord, {
 44→          added_at: input.now,
 45→        })
 46→        .output("after");
 47→    }
 48→  }
 49→
 50→  return learningRecord;
 51→}
