 53→// ---------------------------------------------------------------------------
 54→// Status transitions
 55→// ---------------------------------------------------------------------------
 56→
 57→export async function updateLearningStatus(input: {
 58→  surreal: Surreal;
 59→  workspaceRecord: RecordId<"workspace", string>;
 60→  learningRecord: LearningRecord;
 61→  newStatus: LearningStatus;
 62→  now: Date;
 63→  actorRecord?: RecordId<"identity", string>;
 64→  reason?: string;
 65→}): Promise<void> {
 66→  const row = await input.surreal.select<{ workspace: RecordId<"workspace", string>; status: LearningStatus }>(input.learningRecord);
 67→  if (!row) {
 68→    throw new Error(`learning not found: ${input.learningRecord.id as string}`);
 69→  }
 70→
 71→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
 72→    throw new Error("learning is outside the current workspace scope");
 73→  }
 74→
 75→  const auditFields = buildAuditFields(input.newStatus, input.now, input.actorRecord, input.reason);
 76→
 77→  await input.surreal.update(input.learningRecord).merge({
 78→    status: input.newStatus,
 79→    updated_at: input.now,
 80→    ...auditFields,
 81→  });
 82→}
 83→
 84→function buildAuditFields(
 85→  newStatus: LearningStatus,
 86→  now: Date,
 87→  actorRecord?: RecordId<"identity", string>,
 88→  reason?: string,
 89→): Record<string, unknown> {
 90→  switch (newStatus) {
 91→    case "active":
 92→      return {
 93→        activated_at: now,
 94→        ...(actorRecord ? { approved_by: actorRecord } : {}),
 95→        approved_at: now,
 96→      };
 97→    case "dismissed":
 98→      return {
 99→        dismissed_at: now,
100→        ...(actorRecord ? { dismissed_by: actorRecord } : {}),
101→        ...(reason ? { dismissed_reason: reason } : {}),
102→      };
103→    case "deactivated":
104→      return {
105→        deactivated_at: now,
106→        ...(actorRecord ? { deactivated_by: actorRecord } : {}),
107→      };
108→    case "superseded":
109→      return {};
110→    case "pending_approval":
111→      return {};
112→  }
113→}
