115→// ---------------------------------------------------------------------------
116→// Supersession
117→// ---------------------------------------------------------------------------
118→
119→export async function supersedeLearning(input: {
120→  surreal: Surreal;
121→  workspaceRecord: RecordId<"workspace", string>;
122→  oldLearningRecord: LearningRecord;
123→  newLearningRecord: LearningRecord;
124→  reason?: string;
125→  now: Date;
126→}): Promise<void> {
127→  // Validate workspace scope for old learning
128→  const oldRow = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(input.oldLearningRecord);
129→  if (!oldRow) {
130→    throw new Error(`learning not found: ${input.oldLearningRecord.id as string}`);
131→  }
132→  if ((oldRow.workspace.id as string) !== (input.workspaceRecord.id as string)) {
133→    throw new Error("learning is outside the current workspace scope");
134→  }
135→
136→  // Deactivate old learning
137→  await input.surreal.update(input.oldLearningRecord).merge({
138→    status: "superseded" satisfies LearningStatus,
139→    updated_at: input.now,
140→  });
141→
142→  // Create supersedes edge: new -> old
143→  await input.surreal
144→    .relate(input.newLearningRecord, new RecordId("supersedes", randomUUID()), input.oldLearningRecord, {
145→      superseded_at: input.now,
146→      ...(input.reason ? { reason: input.reason } : {}),
147→    })
148→    .output("after");
149→}
