155→export async function listWorkspaceActiveLearnings(input: {
156→  surreal: Surreal;
157→  workspaceRecord: RecordId<"workspace", string>;
158→  agentType?: string;
159→}): Promise<LearningSummary[]> {
160→  const agentClause = input.agentType
161→    ? "AND (array::len(target_agents) = 0 OR $agentType IN target_agents)"
162→    : "";
163→
164→  const query = [
165→    "SELECT id, text, learning_type, status, source, priority, target_agents,",
166→    "suggested_by, pattern_confidence, created_at, approved_at, dismissed_at,",
167→    "dismissed_reason, deactivated_at",
168→    "FROM learning",
169→    "WHERE workspace = $workspace",
170→    'AND status = "active"',
171→    agentClause,
172→    "ORDER BY created_at DESC;",
173→  ].filter(Boolean).join(" ");
174→
175→  const [rows] = await input.surreal
176→    .query<[LearningRow[]]>(query, {
177→      workspace: input.workspaceRecord,
178→      ...(input.agentType ? { agentType: input.agentType } : {}),
179→    })
180→    .collect<[LearningRow[]]>();
181→
182→  return rows.map(toLearning);
