 97→async function handleCreateLearning(
 98→  deps: ServerDependencies,
 99→  workspaceId: string,
100→  request: Request,
101→): Promise<Response> {
102→  const bodyOrError = await parseJsonBody<CreateBody>(request);
103→  if (isResponse(bodyOrError)) return bodyOrError;
104→  const body = bodyOrError;
105→
106→  // Validate required fields
107→  if (!body.text || typeof body.text !== "string" || body.text.trim().length === 0) {
108→    return jsonError("text is required", 400);
109→  }
110→  if (!body.learning_type || !LEARNING_TYPES.includes(body.learning_type as LearningType)) {
111→    return jsonError(
112→      `learning_type must be one of: ${LEARNING_TYPES.join(", ")}`,
113→      400,
114→    );
115→  }
116→
117→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "learning.create.workspace_resolve.failed");
118→  if (isResponse(workspaceOrError)) return workspaceOrError;
119→  const workspaceRecord = workspaceOrError;
120→
121→  try {
122→    const now = new Date();
123→
124→    // Run collision detection using BM25 fulltext search (no embedding needed)
125→    const collisionResult = await checkCollisions({
126→      surreal: deps.surreal,
127→      model: deps.extractionModel,
128→      workspaceRecord,
129→      learningText: body.text.trim(),
130→      source: "human",
131→    });
132→
133→    // Determine status: blocked learnings stay pending, otherwise human-created = active
134→    const shouldBlock = collisionResult.hasBlockingCollision;
135→    const learningRecord = await createLearning({
136→      surreal: deps.surreal,
137→      workspaceRecord,
138→      learning: {
139→        text: body.text.trim(),
140→        learningType: body.learning_type as LearningType,
141→        priority: (body.priority as "low" | "medium" | "high") ?? "medium",
142→        targetAgents: body.target_agents ?? [],
143→        source: "human",
144→        ...(shouldBlock ? { forceStatus: "pending_approval" as const } : {}),
145→      },
146→      now,
147→    });
148→
149→    const learningId = learningRecord.id as string;
150→
151→    log.info("learning.created", "Learning created via HTTP", {
152→      workspaceId,
153→      learningId,
154→      learningType: body.learning_type,
155→      collisions: collisionResult.collisions.length,
156→      blocked: shouldBlock,
157→    });
158→
159→    const responseCollisions: CollisionResult[] = collisionResult.collisions;
160→
161→    return jsonResponse({
162→      learningId,
163→      learning: { id: learningId },
164→      collisions: responseCollisions,
165→    }, 201);
166→  } catch (error) {
167→    log.error("learning.create.failed", "Failed to create learning", error, { workspaceId });
168→    return jsonError("failed to create learning", 500);
169→  }
170→}
