226→// ---------------------------------------------------------------------------
227→
228→type ActionBody = {
229→  action?: string;
230→  reason?: string;
231→  new_text?: string;
232→};
233→
234→async function handleLearningAction(
235→  deps: ServerDependencies,
236→  workspaceId: string,
237→  learningId: string,
238→  request: Request,
239→): Promise<Response> {
240→  const bodyOrError = await parseJsonBody<ActionBody>(request);
241→  if (isResponse(bodyOrError)) return bodyOrError;
242→  const body = bodyOrError;
243→
244→  if (!body.action || !(VALID_ACTIONS as readonly string[]).includes(body.action)) {
245→    return jsonError(
246→      `action must be one of: ${VALID_ACTIONS.join(", ")}`,
247→      400,
248→    );
249→  }
250→
251→  const action = body.action as LearningAction;
252→
253→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "learning.action.workspace_resolve.failed");
254→  if (isResponse(workspaceOrError)) return workspaceOrError;
255→  const workspaceRecord = workspaceOrError;
256→
257→  // Look up the learning
258→  const learningRecord = new RecordId("learning", learningId) as LearningRecord;
259→  let existing: { status: LearningStatus; workspace: RecordId<"workspace", string> } | undefined;
260→  try {
261→    existing = await deps.surreal.select<{
262→      status: LearningStatus;
263→      workspace: RecordId<"workspace", string>;
264→    }>(learningRecord);
265→  } catch {
266→    // select returns undefined if not found
267→  }
268→
269→  if (!existing) {
270→    return jsonError("learning not found", 404);
271→  }
272→
273→  // Verify workspace scope
274→  if ((existing.workspace.id as string) !== (workspaceRecord.id as string)) {
275→    return jsonError("learning not found", 404);
276→  }
277→
278→  // Validate state transition
279→  const transitions = VALID_TRANSITIONS[existing.status];
280→  if (!transitions || !(action in transitions)) {
281→    return jsonError(
282→      `cannot ${action} a learning in status '${existing.status}'`,
283→      409,
284→    );
285→  }
286→
287→  const newStatus = transitions[action];
288→  const now = new Date();
289→
290→  try {
291→    // If approving with new_text, update text first
292→    if (action === "approve" && body.new_text) {
293→      await updateLearningText({
294→        surreal: deps.surreal,
295→        learningRecord,
296→        newText: body.new_text,
297→        now,
298→      });
299→    }
300→
301→    await updateLearningStatus({
302→      surreal: deps.surreal,
303→      workspaceRecord,
304→      learningRecord,
305→      newStatus,
306→      now,
307→      reason: body.reason,
308→    });
309→
310→    log.info("learning.action.completed", "Learning action completed", {
311→      workspaceId,
312→      learningId,
313→      action,
314→      previousStatus: existing.status,
315→      newStatus,
316→    });
317→
318→    return jsonResponse({ status: newStatus }, 200);
319→  } catch (error) {
320→    log.error("learning.action.failed", "Failed to perform learning action", error, {
321→      workspaceId,
322→      learningId,
323→      action,
324→    });
325→    return jsonError("failed to perform action", 500);
326→  }
327→}
