 91→/**
 92→ * Apply the base schema to a SurrealDB instance.
 93→ *
 94→ * DEFINE ANALYZER cannot run inside a transaction in SurrealDB v3.0+.
 95→ * The SDK may treat a multi-statement .query() as an implicit transaction,
 96→ * causing the analyzer and dependent FULLTEXT indexes to fail silently.
 97→ *
 98→ * We split the schema into three phases:
 99→ * 1. DEFINE ANALYZER (must run outside any transaction)
100→ * 2. Schema definitions (DEFINE TABLE/FIELD/INDEX) — batch is fine
101→ * 3. Seed data (CREATE statements) — separate batch to isolate from index errors
102→ */
103→export async function applyTestSchema(surreal: Surreal): Promise<void> {
104→  const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
105→
106→  // Strip full-line comments before splitting — comments may contain semicolons
107→  // (e.g. "-- The edge is the source of truth; status is a derived consequence.")
108→  // which would create spurious fragments after the split.
109→  const withoutComments = schemaSql
110→    .split("\n")
111→    .filter((line) => !line.trimStart().startsWith("--"))
112→    .join("\n");
113→
114→  // Brace-aware split: only split on `;` outside `{...}` blocks.
115→  // DEFINE FUNCTION and DEFINE EVENT bodies contain semicolons that must not
116→  // be treated as statement terminators.
117→  const statements = splitSqlStatements(withoutComments);
118→
119→  // Phase 1: DEFINE ANALYZER (must be isolated)
120→  const analyzerStmts = statements.filter((s) => s.startsWith("DEFINE ANALYZER"));
121→  for (const stmt of analyzerStmts) {
122→    await surreal.query(stmt + ";");
123→  }
124→
125→  // Phase 2: Schema definitions (DEFINE TABLE/FIELD/INDEX/FUNCTION/EVENT)
126→  const schemaStmts = statements.filter(
127→    (s) => !s.startsWith("DEFINE ANALYZER") && !s.startsWith("CREATE"),
128→  );
129→  if (schemaStmts.length > 0) {
130→    await surreal.query(schemaStmts.map((s) => s + ";").join("\n"));
131→  }
132→
133→  // Phase 3: Seed data (CREATE statements) — isolated so index issues don't block seeds
134→  const seedStmts = statements.filter((s) => s.startsWith("CREATE"));
135→  if (seedStmts.length > 0) {
136→    await surreal.query(seedStmts.map((s) => s + ";").join("\n"));
137→  }
138→}
