447→/**
448→ * Obtain an OAuth2 JWT access token for MCP endpoints.
449→ * Requires a SurrealDB connection to skip consent screen.
450→ */
451→export async function getOAuthToken(
452→  baseUrl: string,
453→  surreal: Surreal,
454→  sessionHeaders: Record<string, string>,
455→  scopes: string = "graph:read graph:reason session:write offline_access",
456→): Promise<string> {
457→  // Trigger JWKS key generation if not yet done
458→  await fetch(`${baseUrl}/api/auth/jwks`);
459→
460→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
461→    method: "POST",
462→    headers: { "Content-Type": "application/json" },
463→    body: JSON.stringify({
464→      client_name: `test-client-${Date.now()}`,
465→      redirect_uris: ["http://127.0.0.1:9999/callback"],
466→      grant_types: ["authorization_code", "refresh_token"],
467→      response_types: ["code"],
468→      token_endpoint_auth_method: "none",
469→    }),
470→  });
471→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
472→
473→  const { client_id } = (await dcrRes.json()) as { client_id: string };
474→
475→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
476→    cid: client_id,
477→  });
478→
479→  const { verifier, challenge } = generatePkce();
480→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
481→  authUrl.searchParams.set("client_id", client_id);
482→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
483→  authUrl.searchParams.set("response_type", "code");
484→  authUrl.searchParams.set("scope", scopes);
485→  authUrl.searchParams.set("state", "test-state");
486→  authUrl.searchParams.set("code_challenge", challenge);
487→  authUrl.searchParams.set("code_challenge_method", "S256");
488→  authUrl.searchParams.set("resource", baseUrl);
489→
490→  const authRes = await fetch(authUrl.toString(), {
491→    headers: sessionHeaders,
492→    redirect: "manual",
493→  });
494→  if (authRes.status !== 302) throw new Error(`Authorize did not redirect: ${authRes.status}`);
495→
496→  const location = authRes.headers.get("location")!;
497→  const redirectUrl = new URL(location, baseUrl);
498→  const code = redirectUrl.searchParams.get("code") ?? "";
499→  if (!code) throw new Error(`No code in redirect: ${location}`);
500→
501→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
502→    method: "POST",
503→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
504→    body: new URLSearchParams({
505→      grant_type: "authorization_code",
506→      code,
507→      redirect_uri: "http://127.0.0.1:9999/callback",
508→      client_id,
509→      code_verifier: verifier,
510→      resource: baseUrl,
511→    }),
512→  });
513→  if (!tokenRes.ok) throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
514→
515→  const tokens = (await tokenRes.json()) as { access_token: string };
516→  return tokens.access_token;
517→}
