713→// ---------------------------------------------------------------------------
714→// DPoP Helpers
715→// ---------------------------------------------------------------------------
716→
717→async function generateDPoPKeyPair(): Promise<DPoPKeyPair> {
718→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
719→    { name: "ECDSA", namedCurve: "P-256" },
720→    true,
721→    ["sign", "verify"],
722→  );
723→
724→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
725→  const thumbprint = await computeDPoPThumbprint(publicJwk);
726→
727→  return { privateKey, publicKey, publicJwk, thumbprint };
728→}
729→
730→async function computeDPoPThumbprint(publicJwk: JsonWebKey): Promise<string> {
731→  const thumbprintInput = JSON.stringify({
732→    crv: publicJwk.crv,
733→    kty: publicJwk.kty,
734→    x: publicJwk.x,
735→    y: publicJwk.y,
736→  });
737→
738→  const hashBuffer = await crypto.subtle.digest(
739→    "SHA-256",
740→    new TextEncoder().encode(thumbprintInput),
741→  );
742→
743→  return base64urlBytes(new Uint8Array(hashBuffer));
744→}
745→
746→async function createDPoPProof(
747→  keyPair: DPoPKeyPair,
748→  method: string,
749→  targetUri: string,
750→): Promise<string> {
751→  const header = {
752→    typ: "dpop+jwt" as const,
753→    alg: "ES256" as const,
754→    jwk: {
755→      kty: keyPair.publicJwk.kty,
756→      crv: keyPair.publicJwk.crv,
757→      x: keyPair.publicJwk.x,
758→      y: keyPair.publicJwk.y,
759→    },
760→  };
761→
762→  const payload = {
763→    jti: crypto.randomUUID(),
764→    htm: method,
765→    htu: targetUri,
766→    iat: Math.floor(Date.now() / 1000),
767→  };
768→
769→  const importedKey = await jose.importJWK(
770→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
771→    "ES256",
772→  );
773→
774→  return await new jose.SignJWT(payload)
775→    .setProtectedHeader(header)
776→    .sign(importedKey);
777→}
778→
779→function base64urlBytes(bytes: Uint8Array): string {
780→  const binary = String.fromCharCode(...bytes);
781→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
782→}
783→
784→// ---------------------------------------------------------------------------
785→// Internal Utilities
786→// ---------------------------------------------------------------------------
787→
788→function requireTestEnv(name: string): string {
789→  const value = process.env[name];
790→  if (!value || value.trim().length === 0) {
791→    throw new Error(`Acceptance test requires env var ${name}`);
792→  }
793→  return value;
794→}
795→
796→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
797→  return await Promise.race([
798→    callback(),
799→    new Promise<T>((_, reject) => {
800→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
801→    }),
802→  ]);
803→}
