// ---------------------------------------------------------------------------

export type SkillStatus = "draft" | "active" | "deprecated";
export type SkillSourceType = "github" | "git";

export type SkillSource = {
  readonly type: SkillSourceType;
  readonly source: string;
  readonly ref?: string;
  readonly subpath?: string;
  readonly skills?: string[];
};

export type CreateSkillInput = {
  name: string;
  description: string;
  version: string;
  source: SkillSource;
  required_tool_ids?: string[];
};

export type SkillListItem = {
  id: string;
  name: string;
  description: string;
  version: string;
  status: SkillStatus;
  source: SkillSource;
  required_tools: Array<{ id: string; name: string }>;
  agent_count: number;
  created_at: string;
};

export type SkillDetailResponse = {
  skill: SkillListItem & {
    created_by?: string;
    updated_at?: string;
  };
  required_tools: Array<{ id: string; name: string }>;
  agents: Array<{ id: string; name: string }>;
  governed_by: Array<{ id: string; name: string; status: string }>;
