437→ */
438→export async function resolveSkillDerivedTools(
439→  surreal: Surreal,
440→  identityId: string,
441→): Promise<Array<{ tool_id: string; tool_name: string; skill_name: string }>> {
442→  const identityRecord = new RecordId("identity", identityId);
443→  const [rows] = await surreal.query<[Array<{
