449→       out.id AS tool_id,
450→       out.name AS tool_name,
451→       in.name AS skill_name
452→     FROM skill_requires
453→     WHERE in IN (SELECT VALUE out FROM possesses WHERE in = $identity AND out.status = "active");`,
454→    { identity: identityRecord },
455→  );
456→  return rows.map((r) => ({
